1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE = 10;
3	const BLOCK_OF_THREE_PREMIUM = 60;
4	const BLOCK_SIZE = 3;
5	const CURSE_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	const LOYALTY_DISCOUNT_RATE = 0.2;
9	const LOYALTY_YEARS_THRESHOLD = 2;
10	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
11	
12	const BASE_PREMIUMS: Record<string, number> = {
13	  sword: 100,
14	  amulet: 60,
15	  staff: 80,
16	  potion: 40,
17	  rune: 25,
18	  moonstone: 25,
19	};
20	
21	type Item = { type: string; cursed?: boolean; enchantment?: number };
22	
23	function isHighlyEnchanted(item: Item): boolean {
24	  return item.enchantment !== undefined && item.enchantment >= HIGH_ENCHANTMENT_THRESHOLD;
25	}
26	
27	function surchargeRate(item: Item): number {
28	  return (item.cursed ? CURSE_SURCHARGE_RATE : 0)
29	    + (isHighlyEnchanted(item) ? HIGH_ENCHANTMENT_SURCHARGE_RATE : 0);
30	}
31	
32	function itemBasePremium(item: Item): number {
33	  const base = BASE_PREMIUMS[item.type];
34	  return base + base * surchargeRate(item);
35	}
36	
37	function sumIndividualBasePremiums(items: Item[]): number {
38	  return items.reduce((sum, item) => sum + itemBasePremium(item), 0);
39	}
40	
41	function groupByType(items: Item[]): Record<string, Item[]> {
42	  const groups: Record<string, Item[]> = {};
43	  for (const item of items) {
44	    if (!groups[item.type]) groups[item.type] = [];
45	    groups[item.type].push(item);
46	  }
47	  return groups;
48	}
49	
50	function premiumForGroup(groupItems: Item[]): number {
51	  return groupItems.length === BLOCK_SIZE
52	    ? BLOCK_OF_THREE_PREMIUM
53	    : sumIndividualBasePremiums(groupItems);
54	}
55	
56	function calculateBasePremium(items: Item[]): number {
57	  const groups = groupByType(items);
58	  return Object.values(groups).reduce((total, group) => total + premiumForGroup(group), 0);
59	}
60	
61	function loyaltyDiscount(basePremium: number, years: number): number {
62	  return years >= LOYALTY_YEARS_THRESHOLD ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
63	}
64	
65	function followUpDiscount(basePremium: number, priorContract: boolean): number {
66	  return priorContract ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
67	}
68	
69	export function quote({ items, years, priorContract }: { items: Item[]; years: number; priorContract: boolean }): { premium: number } {
70	  const basePremium = calculateBasePremium(items);
71	  const totalDiscounts = loyaltyDiscount(basePremium, years) + followUpDiscount(basePremium, priorContract);
72	  const firstInsuranceSurcharges = items.length * FIRST_INSURANCE_SURCHARGE;
73	  return { premium: basePremium - totalDiscounts + firstInsuranceSurcharges + PROCESSING_FEE };
74	}
75	
76	export function claim(_input: unknown): unknown {
77	  return undefined;
78	}
